import React, { useEffect, useMemo, useState } from 'react'
import { pondService, userService } from '../../services/api'
import '../../styles/dashboard.css'
import '../../styles/manager/manager-common.css'
import '../../styles/manager/manager-ponds.css'
import '../../styles/owner/owner-common.css'

const emptyForm = {
  pondCode: '',
  pondName: '',
  area_m2: '',
  depth_m: '',
  max_density: '',
  assigned_staff: '',
}

const formatRoundedNumber = (value) => {
  if (value === null || value === undefined || value === '') return '-'
  const numberValue = Number(value)
  if (Number.isNaN(numberValue)) return value
  return String(Math.round(numberValue))
}

const OwnerPonds = () => {
  const [ponds, setPonds] = useState([])
  const [staffList, setStaffList] = useState([])
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')
  const [success, setSuccess] = useState('')
  const [showModal, setShowModal] = useState(false)
  const [editingPond, setEditingPond] = useState(null)
  const [form, setForm] = useState(emptyForm)

  useEffect(() => {
    fetchData()
  }, [])

  const fetchData = async () => {
    try {
      setLoading(true)
      const [pondRes, staffRes] = await Promise.all([
        pondService.getAllPonds(),
        userService.getWorkers(),
      ])
      setPonds(pondRes?.data?.data || [])
      const workers = staffRes?.data?.data || []
      setStaffList(workers)
      setError('')
    } catch (err) {
      const errorMsg = err?.response?.data?.message || 'KhÃ´ng táº£i Ä‘Æ°á»£c dá»¯ liá»‡u ao nuÃ´i'
      setError(errorMsg)
    } finally {
      setLoading(false)
    }
  }

  const staffOptions = useMemo(() => {
    return staffList.map((staff) => ({
      id: staff.user_id,
      name: staff.full_name || staff.username,
    }))
  }, [staffList])

  const getStaffName = (id) => {
    if (!id) return '-'
    const found = staffOptions.find((s) => String(s.id) === String(id))
    return found ? found.name : '-'
  }

  const openCreateModal = () => {
    setEditingPond(null)
    setForm(emptyForm)
    setError('')
    setSuccess('')
    setShowModal(true)
  }

  const openEditModal = (pond) => {
    setEditingPond(pond)
    setForm({
      pondCode: pond.pond_code || '',
      pondName: pond.pond_name || '',
      area_m2: pond.area_m2 ?? '',
      depth_m: pond.depth_m ?? '',
      max_density: pond.max_density ?? '',
      assigned_staff: pond.assigned_staff || '',
    })
    setError('')
    setSuccess('')
    setShowModal(true)
  }

  const handleChange = (field, value) => {
    setForm((prev) => ({ ...prev, [field]: value }))
  }

  const handleSubmit = async (event) => {
    event.preventDefault()
    try {
      setSaving(true)
      setError('')
      setSuccess('')
      const payload = {
        pondCode: form.pondCode.trim() || undefined,
        pondName: form.pondName.trim(),
        areaMeter: Number(form.area_m2),
        depthMeter: Number(form.depth_m),
        maxDensity: Number(form.max_density),
        assignedStaff: form.assigned_staff ? Number(form.assigned_staff) : null,
      }

      if (editingPond) {
        await pondService.updatePond(editingPond.pond_id, payload)
        setSuccess('Cáº­p nháº­t ao nuÃ´i thÃ nh cÃ´ng')
      } else {
        await pondService.createPond(payload)
        setSuccess('Táº¡o ao nuÃ´i thÃ nh cÃ´ng')
      }

      setShowModal(false)
      setEditingPond(null)
      setForm(emptyForm)
      await fetchData()
    } catch (err) {
      setError(err?.response?.data?.message || 'Lá»—i khi lÆ°u dá»¯ liá»‡u')
    } finally {
      setSaving(false)
    }
  }

  const handleDelete = async (pondId) => {
    if (window.confirm('Báº¡n cháº¯c cháº¯n muá»‘n xÃ³a ao nuÃ´i nÃ y?')) {
      try {
        setError('')
        setSuccess('')
        await pondService.deletePond(pondId)
        setSuccess('XÃ³a ao nuÃ´i thÃ nh cÃ´ng')
        await fetchData()
      } catch (err) {
        setError(err?.response?.data?.message || 'Lá»—i khi xÃ³a ao nuÃ´i')
      }
    }
  }

  if (loading) {
    return (
      <div className="owner-ponds owner-page">
        <div className="flex-center" style={{ height: '100vh' }}>
          <div className="spinner"></div>
        </div>
      </div>
    )
  }

  return (
    <div className="owner-ponds owner-page">
      <div className="owner-page__header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '16px' }}>
        <div>
          <h1>Quáº£n lÃ½ ao nuÃ´i</h1>
          <p>Tá»•ng sá»‘ ao: {ponds.length}</p>
        </div>
        <button onClick={openCreateModal} className="btn btn-primary">
          âž• ThÃªm ao má»›i
        </button>
      </div>

      {error && <div className="alert alert-error">{error}</div>}
      {success && <div className="alert alert-success">{success}</div>}

      <div className="card">
        <table className="data-table" style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ borderBottom: '2px solid #ddd' }}>
              <th style={{ padding: '12px', textAlign: 'left', fontWeight: 600 }}>MÃ£ ao</th>
              <th style={{ padding: '12px', textAlign: 'left', fontWeight: 600 }}>TÃªn ao</th>
              <th style={{ padding: '12px', textAlign: 'left', fontWeight: 600 }}>Diá»‡n tÃ­ch (mÂ²)</th>
              <th style={{ padding: '12px', textAlign: 'left', fontWeight: 600 }}>Äá»™ sÃ¢u (m)</th>
              <th style={{ padding: '12px', textAlign: 'left', fontWeight: 600 }}>Máº­t Ä‘á»™ tá»‘i Ä‘a</th>
              <th style={{ padding: '12px', textAlign: 'left', fontWeight: 600 }}>NgÆ°á»i phá»¥ trÃ¡ch</th>
              <th style={{ padding: '12px', textAlign: 'center', fontWeight: 600 }}>HÃ nh Ä‘á»™ng</th>
            </tr>
          </thead>
          <tbody>
            {ponds.length === 0 ? (
              <tr>
                <td colSpan="7" style={{ padding: '32px', textAlign: 'center', color: '#999' }}>
                  KhÃ´ng cÃ³ ao nuÃ´i nÃ o. HÃ£y táº¡o ao má»›i Ä‘á»ƒ báº¯t Ä‘áº§u!
                </td>
              </tr>
            ) : (
              ponds.map((pond) => (
                <tr key={pond.pond_id} style={{ borderBottom: '1px solid #eee' }}>
                  <td style={{ padding: '12px' }}>{pond.pond_code}</td>
                  <td style={{ padding: '12px' }}>{pond.pond_name}</td>
                  <td style={{ padding: '12px' }}>{formatRoundedNumber(pond.area_m2)}</td>
                  <td style={{ padding: '12px' }}>{formatRoundedNumber(pond.depth_m)}</td>
                  <td style={{ padding: '12px' }}>{formatRoundedNumber(pond.max_density)}</td>
                  <td style={{ padding: '12px' }}>{getStaffName(pond.assigned_staff)}</td>
                  <td style={{ padding: '12px', textAlign: 'center' }}>
                    <button
                      onClick={() => openEditModal(pond)}
                      className="btn btn-secondary"
                      style={{ marginRight: '8px', padding: '4px 8px', fontSize: '0.85rem' }}
                    >
                      âœï¸ Sá»­a
                    </button>
                    <button
                      onClick={() => handleDelete(pond.pond_id)}
                      className="btn btn-danger"
                      style={{ padding: '4px 8px', fontSize: '0.85rem' }}
                    >
                      ðŸ—‘ï¸ XÃ³a
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {showModal && (
        <div className="modal">
          <div className="modal-content owner-page__modal">
            <h2 className="owner-page__section-title">{editingPond ? 'Sá»­a ao nuÃ´i' : 'Táº¡o ao nuÃ´i má»›i'}</h2>
            <form onSubmit={handleSubmit}>
              <div className="owner-page__form-grid">
                {editingPond && (
                  <div className="owner-page__form-group owner-page__form-group--full">
                    <label htmlFor="pondCode">MÃ£ ao</label>
                    <input
                      id="pondCode"
                      type="text"
                      value={form.pondCode}
                      onChange={(e) => handleChange('pondCode', e.target.value)}
                      placeholder="Äá»ƒ trá»‘ng Ä‘á»ƒ tá»± sinh"
                    />
                  </div>
                )}
                <div className="owner-page__form-group">
                  <label htmlFor="pondName">TÃªn ao *</label>
                  <input
                    id="pondName"
                    type="text"
                    value={form.pondName}
                    onChange={(e) => handleChange('pondName', e.target.value)}
                    placeholder="Nháº­p tÃªn ao"
                    required
                  />
                </div>
                <div className="owner-page__form-group">
                  <label htmlFor="area_m2">Diá»‡n tÃ­ch (mÂ²) *</label>
                  <input
                    id="area_m2"
                    type="number"
                    value={form.area_m2}
                    onChange={(e) => handleChange('area_m2', e.target.value)}
                    placeholder="Nháº­p diá»‡n tÃ­ch"
                    required
                  />
                </div>
                <div className="owner-page__form-group">
                  <label htmlFor="depth_m">Äá»™ sÃ¢u (m) *</label>
                  <input
                    id="depth_m"
                    type="number"
                    value={form.depth_m}
                    onChange={(e) => handleChange('depth_m', e.target.value)}
                    placeholder="Nháº­p Ä‘á»™ sÃ¢u"
                    required
                  />
                </div>
                <div className="owner-page__form-group">
                  <label htmlFor="max_density">Máº­t Ä‘á»™ tá»‘i Ä‘a *</label>
                  <input
                    id="max_density"
                    type="number"
                    value={form.max_density}
                    onChange={(e) => handleChange('max_density', e.target.value)}
                    placeholder="Nháº­p máº­t Ä‘á»™ tá»‘i Ä‘a"
                    required
                  />
                </div>
                <div className="owner-page__form-group">
                  <label htmlFor="assigned_staff">NgÆ°á»i phá»¥ trÃ¡ch (tÃ¹y chá»n)</label>
                  {staffOptions.length === 0 ? (
                    <div style={{ padding: '10px', backgroundColor: '#f0f0f0', borderRadius: '4px', color: '#666', fontSize: '0.9rem' }}>
                      â„¹ï¸ ChÆ°a cÃ³ nhÃ¢n viÃªn nÃ o. HÃ£y táº¡o nhÃ¢n viÃªn trong trang Quáº£n lÃ½ nhÃ¢n viÃªn.
                    </div>
                  ) : (
                    <select
                      id="assigned_staff"
                      value={form.assigned_staff}
                      onChange={(e) => handleChange('assigned_staff', e.target.value)}
                    >
                      <option value="">-- Chá»n nhÃ¢n viÃªn --</option>
                      {staffOptions.map((staff) => (
                        <option key={staff.id} value={staff.id}>
                          {staff.name}
                        </option>
                      ))}
                    </select>
                  )}
                </div>
              </div>
              <div className="owner-page__actions">
                <button
                  type="button"
                  onClick={() => setShowModal(false)}
                  className="btn btn-secondary"
                  disabled={saving}
                >
                  Há»§y
                </button>
                <button type="submit" className="btn btn-primary" disabled={saving}>
                  {saving ? 'Äang lÆ°u...' : editingPond ? 'Cáº­p nháº­t' : 'Táº¡o má»›i'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}

export default OwnerPonds
